mapper.select:
SELECT la.*, u.name as user_name, u.username as user_username
FROM leave_application la
LEFT JOIN user u ON la.user_id = u.id
WHERE la.user_id = #{userId}

    AND la.status = #{status}


    AND la.type = #{type}


    AND la.start_time >= #{startTime}


    AND la.end_time <= #{endTime}

ORDER BY la.create_time DESC

SELECT la.*, u.name as user_name, u.username as user_username
FROM leave_application la
LEFT JOIN user u ON la.user_id = u.id
WHERE u.class_id = #{classId}

    AND la.status = #{status}


    AND la.type = #{type}


    AND la.start_time >= #{startTime}


    AND la.end_time <= #{endTime}

ORDER BY la.create_time DESC

SELECT la.*, u.name as user_name, u.username as user_username
FROM leave_application la
LEFT JOIN user u ON la.user_id = u.id
WHERE u.college_id = #{collegeId}

    AND la.status = #{status}


    AND la.type = #{type}


    AND la.start_time >= #{startTime}


    AND la.end_time <= #{endTime}

ORDER BY la.create_time DESC

SELECT la.*, u.name as user_name, u.username as user_username
FROM leave_application la
LEFT JOIN user u ON la.user_id = u.id
WHERE 1=1

    AND la.status = #{status}


    AND la.type = #{type}


    AND la.start_time >= #{startTime}


    AND la.end_time <= #{endTime}

ORDER BY la.create_time DESC

SELECT COUNT(*) FROM leave_application
WHERE user_id = #{userId}
AND status IN ('PENDING', 'APPROVED')
AND NOT EXISTS (SELECT 1 FROM leave_return lr WHERE lr.leave_id = leave_application.id)
AND (
    (start_time <= #{startTime} AND end_time >= #{startTime})
    OR (start_time <= #{endTime} AND end_time >= #{endTime})
    OR (start_time >= #{startTime} AND end_time <= #{endTime})
)

    AND id != #{excludeId}
